class Solution {
    func minCost(maxTime: Int64, edges: Array<Array<Int64>>, passingFees: Array<Int64>): Int64 {
        let n = passingFees.size
        let infinity = Int.Max >> 1
        var f = Array<Array<Int64>>(maxTime + 1, {_ => Array<Int64>(n, item: infinity)})
        f[0][0] = passingFees[0]
        for (t in 1..= maxTime) {
            for (edge in edges) {
                let i = edge[0]
                let j = edge[1]
                let cost = edge[2]
                if (cost <= t) {
                    f[t][i] = min(f[t][i], f[t - cost][j] + passingFees[i])
                    f[t][j] = min(f[t][j], f[t - cost][i] + passingFees[j])
                }
            }
        }

        var ans = infinity
        for (t in 1..= maxTime) {
            ans = min(ans, f[t][n - 1])
        }
        if (ans == infinity) {
            return -1
        }
        return ans
    }
}
```

**复杂度分析**

- 时间复杂度：$O((n+m) \cdot \textit{maxTimes})$，其中 $m$ 是数组 $\textit{edges}$ 的长度。

    - 我们需要 $O(n \cdot \textit{maxTimes})$ 的时间初始化数组 $f$；

    - 动态规划需要的时间为 $O(m \cdot \textit{maxTimes})$。

- 空间复杂度：$O(n \cdot \textit{maxTimes})$。
